\section*{Worked Examples}
\nopagebreak[4]
\begin{samepage}
\begin{examplebox}{Calculating Path Loss in Free Space}
Calculate the path loss for a signal at 2 GHz traveling 100 meters in free space.
\end{examplebox}

\begin{solutionbox}
\textbf{Given Information:}
\begin{itemize}
  \item Frequency: 2 GHz
  \item Distance: 100 m
\end{itemize}

\textbf{Required:} Path loss in dB

\textbf{Solution Steps:}
\begin{enumerate}
  \item \textbf{Convert frequency to wavelength}
  \begin{itemize}
    \item Explanation: Using the relation \(c = f \lambda\), where \(c = 3 \times 10^8\) m/s.
    \item Formula: \(\lambda = \frac{c}{f}\)
    \item Calculation: \(\lambda = \frac{3 \times 10^8 \text{ m/s}}{2 \times 10^9 \text{ Hz}} = 0.15 \text{ m}\)
  \end{itemize}

  \item \textbf{Apply the Friis transmission formula}
  \begin{itemize}
    \item Explanation: The formula in dB form is \(PL = 20 \log_{10}(d) + 20 \log_{10}(f) - 147.55\).
    \item Formula: \(PL = 20 \log_{10}(100) + 20 \log_{10}(2000) - 147.55\)
    \item Calculation: \(PL = 40 + 66.02 - 147.55 = -41.53 \text{ dB}\)
  \end{itemize}
\end{enumerate}

\textbf{Final Answer:} \(\boxed{-41.53 \text{ dB}}\)

\textbf{Teaching Notes:} It's common to confuse the units of frequency in the Friis formula. Ensure to convert GHz to MHz or Hz as required.
\end{solutionbox}
\end{samepage}

