\section*{Worked Examples}
\subsection*{Example 1: Reading a Temperature Sensor}
\textbf{Problem:} How can you use an LM35 sensor with an Arduino to measure temperature and display it on the serial monitor?

\textbf{Solution Steps:}
\begin{enumerate}
    \item \textbf{Connect the LM35 sensor to the Arduino's analog input pin.}
    \item \textbf{Write a program to read analog values from the sensor.}
    \item \textbf{Use the formula:} $$Temperature (°C) = \frac{\text{Analog Value}}{1024} \times 5V / 0.01$$
    \item \textbf{Display the temperature on the serial monitor.}
    \item \textbf{Analyze the impact of ADC resolution on the temperature reading.}
\end{enumerate}
\textbf{Final Answer:} The temperature is measured and displayed in degrees Celsius adjusted for Arduino's ADC limitations.

\subsection*{Example 2: Light Measurement Using a Photoresistor}
\textbf{Problem:} Develop a circuit using a photoresistor to measure light intensity and control a light source accordingly.

\textbf{Solution Steps:}
\begin{enumerate}
    \item \textbf{Connect the photoresistor in a voltage divider configuration to the Arduino.}
    \item \textbf{Implement a program to read analog values and derive light intensity levels.}
    \item \textbf{Set thresholds to control light elements based on intensity.}
    \item \textbf{Discuss noise filtering techniques applicable to this setup.}
    \item \textbf{Graph the intensity changes over time to validate setup.}
\end{enumerate}
\textbf{Final Answer:} Light intensity is measured with the ability to control outputs based on derived thresholds.

\subsection*{Example 3: Calibrated Potentiometer for Brightness Control}
\textbf{Problem:} Describe how to use a potentiometer with Arduino to control LED brightness.

\textbf{Solution Steps:}
\begin{enumerate}
    \item \textbf{Connect a potentiometer to the Arduino's analog input.}
    \item \textbf{Develop a program to read pot values between 0 and 1023.}
    \item \textbf{Map these values to control PWM signals driving an LED:} $$PWM_{\text{value}} = \frac{\text{Analog Value}}{1024} \times \text{Max PWM}$$
    \item \textbf{Observe LED brightness response to pot adjustments.}
    \item \textbf{Document and interpret the observed results to reinforce understanding.}
\end{enumerate}
\textbf{Final Answer:} The potentiometer effectively controls LED brightness by mapping analog values to PWM signals.

\section*{Class Problems}
\subsection*{Problem 1}
\textbf{Problem:} Calculate the ADC value for an LM35 sensor at 25°C, assuming a voltage reference of 5V.

\textbf{Solution Steps:}
\begin{enumerate}
    \item \textbf{Determine the voltage output of the LM35 at 25°C:} $$V_{\text{out}} = 25 \times 0.01 = 0.25V$$
    \item \textbf{Calculate the ADC value:} $$\text{ADC Value} = \frac{0.25}{5} \times 1024 = 51.2 \approx 51$$
\end{enumerate}
\textbf{Expected Answer:} ADC value for 25°C = 51

\subsection*{Problem 2}
\textbf{Problem:} Derive the voltage for a photoresistor reading of 512 on a 10-bit system.

\textbf{Solution Steps:}
\begin{enumerate}
    \item \textbf{Use the formula:} $$Voltage = \frac{\text{Reading}}{1024} \times 5V$$
    \item \textbf{Substitute the reading:} $$Voltage = \frac{512}{1024} \times 5 = 2.5V$$
\end{enumerate}
\textbf{Expected Answer:} Voltage = 2.5V

