    \item In what scenarios would you use definite vs. indefinite integrals?
\end{enumerate}

\section*{Assessment}
\subsection*{Multiple Choice Questions}
\begin{enumerate}
    \item What is the integral of $x^n$ if $n \neq -1$?
    \begin{enumerate}
        \item $\frac{x^{n+1}}{n+1} + C$
        \item $\frac{x^{n+1}}{n-1} + C$
        \item $\ln|x| + C$
        \item $e^x + C$
    \end{enumerate}

    \item Which function is an antiderivative of $\sin(x)$?
    \begin{enumerate}
