\section*{1. Integration by Substitution}

\begin{definitionbox}
Integration by substitution is used to simplify integrals involving composite functions.

If $u = g(x)$, then:
\[
\int f(g(x))g'(x)\,dx = \int f(u)\,du
\]
\end{definitionbox}

%---------------- Example 1 ----------------
\begin{examplebox}
Evaluate:
\[
\int 2x \cos(x^2)\,dx
\]
\end{examplebox}

\begin{solutionbox}
Let:
\[
u = x^2 \quad \Rightarrow \quad du = 2x\,dx
\]

Substitute into the integral:
\[
\int 2x \cos(x^2)\,dx = \int \cos(u)\,du
\]

Integrate:
\[
= \sin(u) + C
\]

Back-substitute:
\[
= \sin(x^2) + C
\]

\[
\boxed{\sin(x^2) + C}
\]
\end{solutionbox}

%---------------- Diagram ----------------
\begin{center}
\begin{tikzpicture}
\begin{axis}[
    width=0.6\linewidth,
    axis lines=middle,
    xlabel={$x$}, ylabel={$y$},
    domain=0:2,
    samples=100,
]
\addplot[blue, thick] {cos(x^2)};
\end{axis}
\end{tikzpicture}
\end{center}

