\section*{2. Integration by Parts}

\begin{definitionbox}
Integration by parts is based on the product rule:
\[
\int u\,dv = uv - \int v\,du
\]
\end{definitionbox}

%---------------- Example 2 ----------------
\begin{examplebox}
Evaluate:
\[
\int x e^x\,dx
\]
\end{examplebox}

\begin{solutionbox}
Let:
\[
u = x \quad \Rightarrow \quad du = dx
\]
\[
dv = e^x dx \quad \Rightarrow \quad v = e^x
\]

Apply the formula:
\[
\int x e^x dx = x e^x - \int e^x dx
\]

\[
= x e^x - e^x + C
\]

\[
= e^x(x - 1) + C
\]

\[
\boxed{e^x(x - 1) + C}
\]
\end{solutionbox}

