\section*{Exercises}

\begin{exercisebox}
\textbf{(Basic)} Evaluate:
\[
\int 3x^2 e^{x^3}\,dx
\]
\end{exercisebox}

\begin{exercisebox}
\textbf{(Intermediate)} Evaluate:
\[
\int x \ln(x)\,dx
\]
\end{exercisebox}

\begin{exercisebox}
\textbf{(Advanced)} Evaluate:
\[
\int x^2 e^x\,dx
\]
\end{exercisebox}

%================================================
\section*{Solutions}

\begin{solutionbox}
\textbf{Exercise 1:}

Let $u = x^3$, then $du = 3x^2 dx$.

\[
\int 3x^2 e^{x^3} dx = \int e^u du = e^u + C = e^{x^3} + C
\]
\end{solutionbox}

\begin{solutionbox}
\textbf{Exercise 2:}

Let:
\[
u = \ln x, \quad dv = x dx
\]

Then:
\[
du = \frac{1}{x}dx, \quad v = \frac{x^2}{2}
\]

\[
\int x \ln x dx = \frac{x^2}{2}\ln x - \int \frac{x^2}{2}\cdot \frac{1}{x} dx
\]

\[
= \frac{x^2}{2}\ln x - \frac{1}{2}\int x dx
\]

\[
= \frac{x^2}{2}\ln x - \frac{x^2}{4} + C
\]
\end{solutionbox}

\begin{solutionbox}
\textbf{Exercise 3:}

Apply integration by parts twice:

Final answer:
\[
\int x^2 e^x dx = e^x(x^2 - 2x + 2) + C
\]
\end{solutionbox}

