\section{Worked Examples}\label{sec:examples}\nopagebreak[4]

\begin{samepage}
\needspace{14\baselineskip}
\begin{examplebox}{Example 1: Understanding Inverse Trigonometric Functions}
What is the derivative of \( \arcsin(x) \)?

\textbf{Given:}
\begin{itemize}
    \item Function \( f(x) = \arcsin(x) \)
\end{itemize}

\textbf{Required:} Find \( f'(x) \).

\begin{figure}[H]
\centering
\begin{tikzpicture}
\begin{axis}[
    axis lines=middle,
    xlabel={$x$},
    ylabel={$y$},
    xtick={-1, 0, 1},
