    ymin=-2, ymax=2,
    xmin=-1.5, xmax=1.5,
    grid=both,
    grid style={dashed, gray!30},
    enlargelimits
]
\addplot[domain=-1:1, samples=100, thick, blue] {asin(x)};
\end{axis}
\end{tikzpicture}
\caption{Graph of \( y = \arcsin(x) \).}
\end{figure}
\end{examplebox}
\begin{solutionbox}
\textbf{Step 1: Identify the derivative formula for \( \arcsin(x) \)}\\
The derivative of \( \arcsin(x) \) is a standard result. It can be derived using implicit differentiation. Recall the derivative formula:
\[
\frac{d}{dx} \arcsin(x) = \frac{1}{\sqrt{1-x^2}}
\]

\textbf{Step 2: Apply the derivative formula}\\
Substitute the known function into the derivative formula. The calculation is direct due to the standard form:
\[
f'(x) = \frac{1}{\sqrt{1-x^2}}
\]

\[\boxed{\frac{1}{\sqrt{1-x^2}}}\]
\end{solutionbox}
\begin{notebox}
Understanding derivatives of inverse functions is crucial. Remember the domain limitations when differentiating. Implicit differentiation is a powerful tool.
\end{notebox}
\end{samepage}

\begin{samepage}
\needspace{14\baselineskip}
\begin{examplebox}{Example 2: Properties of Hyperbolic Functions}
What is the identity for \( \cosh^2(x) - \sinh^2(x) \)?

\textbf{Given:}
\begin{itemize}
    \item Hyperbolic functions: \( \cosh(x) \) and \( \sinh(x) \)
\end{itemize}

\textbf{Required:} Prove the identity \( \cosh^2(x) - \sinh^2(x) = 1 \).

\begin{figure}[H]
\centering
\begin{tikzpicture}
\begin{axis}[
    axis lines=middle,
    xlabel={$x$},
    ylabel={$y$},
    xtick={-2, 0, 2},
    ytick={-2, 0, 2},
    ymin=-3, ymax=3,
    xmin=-2.5, xmax=2.5,
    grid=both,
    grid style={dashed, gray!30},
    enlargelimits
]
\addplot[domain=-2:2, samples=100, thick, red] {cosh(x)};
\addplot[domain=-2:2, samples=100, thick, green] {sinh(x)};
\end{axis}
\end{tikzpicture}
\caption{Graphs of \( \cosh(x) \) and \( \sinh(x) \).}
\end{figure}
\end{examplebox}
\begin{solutionbox}
\textbf{Step 1: Recall the definitions of \( \cosh(x) \) and \( \sinh(x) \)}\\
\[
\cosh(x) = \frac{e^x + e^{-x}}{2}, \quad \sinh(x) = \frac{e^x - e^{-x}}{2}
\]

\textbf{Step 2: Express \( \cosh^2(x) \) and \( \sinh^2(x) \) using definitions}\\
\[
\cosh^2(x) = \left(\frac{e^x + e^{-x}}{2}\right)^2, \quad \sinh^2(x) = \left(\frac{e^x - e^{-x}}{2}\right)^2
\]

\textbf{Step 3: Simplify the expressions and apply the identity}\\
\[
\cosh^2(x) - \sinh^2(x) = \left(\frac{(e^x + e^{-x})^2 - (e^x - e^{-x})^2}{4}\right) = 1
\]

\[\boxed{1}\]
\end{solutionbox}
\begin{notebox}
Hyperbolic identities resemble trigonometric ones. Understanding definitions is crucial for derivations. Useful in various scientific and engineering contexts.
\end{notebox}
\end{samepage}

